// OAuth 2.0 Implicit Flow Client Implementation

// Configuration
const clientId = 'YOUR_CLIENT_ID';
const authorizationEndpoint = 'https://authorization-server.com/auth';
const redirectUri = 'https://your-app.com/callback';
const scope = 'your_scope';

// Initiate Authorization Request
function authorize() {
  const authUrl = `${authorizationEndpoint}?response_type=token&client_id=${encodeURIComponent(clientId)}&redirect_uri=${encodeURIComponent(redirectUri)}&scope=${encodeURIComponent(scope)}`;
  window.location = authUrl;
}

// Extract Access Token from URL
function extractTokenFromUrl() {
  const hash = window.location.hash;
  if (hash) {
    const params = new URLSearchParams(hash.substring(1));
    return params.get('access_token');
  }
  return null;
}

// Store Access Token for Session Duration
function storeToken(token) {
  if (token) {
    sessionStorage.setItem('access_token', token);
  }
}

// Retrieve Stored Token
function getStoredToken() {
  return sessionStorage.getItem('access_token');
}

// Example API Call Using Access Token
function apiCall() {
  const token = getStoredToken();
  if (token) {
    fetch('https://api.yourservice.com/data', {
      headers: {
        'Authorization': `Bearer ${token}`
      }
    })
    .then(response => response.json())
    .then(data => console.log(data))
    .catch(error => console.error('Error:', error));
  } else {
    console.log('No access token available.');
  }
}

// Initialize
(function() {
  const token = extractTokenFromUrl();
  if (token) {
    storeToken(token);
    window.location.hash = '';
  } else if (!getStoredToken()) {
    authorize();
  }
})();

